spec.expr:
sum by (status) (
    label_replace(
        label_replace(
            rate(loki_request_duration_seconds_count{
                service="engine", 
                route=~"(api_prom_rules|api_prom_rules_namespace_groupname|api_v1_rules|loki_api_v1_delete|loki_api_v1_detected_labels|loki_api_v1_index_stats|loki_api_v1_index_volume|loki_api_v1_index_volume_range|loki_api_v1_label_name_values|loki_api_v1_label_values|loki_api_v1_labels|loki_api_v1_patterns|loki_api_v1_query|loki_api_v1_query_range|loki_api_v1_series|prometheus_api_v1_rules)"
            }[$__rate_interval]),
            "status", "${1}xx", "status_code", "([0-9]).."
        ),
        "status", "${1}", "status_code", "([a-zA-Z_]+)"
    )
)
